// Filter craftsmen with rating >= 4.0
const items = $input.all();
return items.filter(item => {
  return item.json.average_rating >= 4.0;
});

// Check if craftsman is START tier (10 tasks/day) or PRO (unlimited)
const items = $input.all();
const today = new Date().toISOString().split('T')[0];

return items.filter(craftsman => {
  if (craftsman.json.tier === 'PRO') return true;
  // For START tier, would need to check daily count
  return craftsman.json.daily_task_count < 10;
});

